def cocktail_sort(arr):
	n = len(arr)
	swapped = True
	start = 0
	end = n - 1
	while swapped:
		swapped = False
		for i in range(start, end):
			if arr[i] > arr[i + 1]:
				arr[i], arr[i + 1] = arr[i + 1], arr[i]
				swapped = True
		if not swapped:
			break
		swapped = False
		end = end - 1
		for i in range(end - 1, start - 1, -1):
			if arr[i] > arr[i + 1]:
				arr[i], arr[i + 1] = arr[i + 1], arr[i]
				swapped = True
		start = start + 1

Code.JavaScript:
function cocktailSort(arr) {
	let swapped = true;
	let start = 0;
	let end = arr.length - 1;
	while (swapped) {
		swapped = false;
		for (let i = start; i < end; i++) {
			if (arr[i] > arr[i + 1]) {
				[arr[i], arr[i + 1]] = [arr[i + 1], arr[i]];
				swapped = true;
			}
		}
		if (!swapped) break;
		swapped = false;
		end--;
		for (let i = end - 1; i >= start; i--) {
			if (arr[i] > arr[i + 1]) {
				[arr[i], arr[i + 1]] = [arr[i + 1], arr[i]];
				swapped = true;
			}
		}
		start++;
	}
}

